+        var maxFreq = wordFrequencies.Count > 0 ? wordFrequencies.Values.Max() : 1;
+
+        return sentences.Select((sentence, index) =>
+        {
+            var words = ExtractWords(sentence);
+            if (words.Count == 0)
+                return (index, 0.0);
+
+            double score = words
+                .Where(w => wordFrequencies.ContainsKey(w))
+                .Sum(w => (double)wordFrequencies[w] / maxFreq);
+
+            return (index, score / words.Count);
+        }).ToList();
+    }
+
+    private static List<string> ExtractWords(string text)
+    {
+        return WordRegex().Matches(text)
+            .Select(m => m.Value)
+            .Where(w => w.Length > 1)
